if (! function_exists('itunes_search')) {
    function itunes_search($term, $media = null, $country = null, $limit = null, $timeout = null)
    {
            $term = $term ?? '';
            $media = $media ?? 'all';
            $country = $country ?? 'US';
            $limit = $limit ?? 10;
            $timeout = $timeout ?? 15;

            $timeout = max(5, min(30, (int)$timeout));
            $limit = max(1, min(50, (int)$limit));
            $term = trim($term);
            $media = strtolower(trim($media));
            $country = strtoupper(trim(substr($country, 0, 2)));

            if (empty($term)) {
                return ['success' => false, 'error' => 'Search term is required.'];
            }

            $valid_media = ['all', 'music', 'movie', 'podcast', 'audiobook', 'tvShow', 'software', 'ebook'];
            if (!in_array($media, $valid_media)) $media = 'all';

            // Helper: fetch JSON
            $fetch_json = function($url, $t) {
                $ctx = stream_context_create([
                    'http' => ['method' => 'GET', 'timeout' => $t, 'header' => "User-Agent: itunes_search/1.0\r\n", 'ignore_errors' => true],
                    'ssl' => ['verify_peer' => false, 'verify_peer_name' => false],
                ]);
                $body = @file_get_contents($url, false, $ctx);
                if ($body === false) return ['error' => error_get_last()['message'] ?? 'fetch failed', 'success' => false];
                $status = 200;
                if (isset($http_response_header)) {
                    foreach ($http_response_header as $h) {
                        if (preg_match('#^HTTP/\d+\.\d+ (\d+)#', $h, $m)) { $status = (int)$m[1]; break; }
                    }
                }
                if ($status >= 400) return ['error' => "HTTP $status", 'success' => false];
                $data = @json_decode($body, true);
                if ($data === null) return ['error' => 'Invalid JSON', 'success' => false];
                return ['data' => $data, 'status' => $status, 'success' => true];
            };

            // Build search URL
            $search_url = 'https://itunes.apple.com/search?term=' . urlencode($term)
                . '&country=' . $country
                . '&media=' . $media
                . '&limit=' . $limit;

            $result = $fetch_json($search_url, $timeout);
            if (!$result['success']) {
                return ['success' => false, 'error' => 'iTunes Search API: ' . $result['error']];
            }

            $data = $result['data'];
            $result_count = $data['resultCount'] ?? 0;
            $results = $data['results'] ?? [];

            $items = [];
            foreach ($results as $item) {
                $wrapper_type = $item['wrapperType'] ?? 'track';
                $kind = $item['kind'] ?? '';

                // Format duration
                $duration_ms = $item['trackTimeMillis'] ?? 0;
                $duration_formatted = '';
                if ($duration_ms > 0) {
                    $mins = floor($duration_ms / 60000);
                    $secs = floor(($duration_ms % 60000) / 1000);
                    $duration_formatted = "{$mins}:{$secs}";
