                    $entry['duration'] = $duration_formatted;
                    $entry['duration_ms'] = $duration_ms;
                }

                if ($media === 'podcast' || $kind === 'podcast') {
                    $entry['genre'] = $item['primaryGenreName'] ?? '';
                    $entry['feed_url'] = $item['feedUrl'] ?? '';
                    $entry['track_count'] = $item['trackCount'] ?? null;
                    $entry['description'] = $item['description'] ?? $item['longDescription'] ?? '';
                    $entry['content_advisory'] = $item['contentAdvisoryRating'] ?? '';
                }

                if ($media === 'audiobook' || $kind === 'audiobook') {
                    $entry['genre'] = $item['primaryGenreName'] ?? '';
                    $entry['description'] = $item['description'] ?? '';
                }

                if ($media === 'ebook' || $kind === 'ebook') {
                    $entry['genre'] = $item['genres'][0] ?? $item['primaryGenreName'] ?? '';
                    $entry['description'] = $item['description'] ?? '';
                    $entry['formatted_price'] = $item['formattedPrice'] ?? '';
                }

                if ($media === 'software' || $kind === 'software') {
