                    $entry['description'] = $item['description'] ?? $item['longDescription'] ?? '';
                    $entry['content_advisory'] = $item['contentAdvisoryRating'] ?? '';
                    $entry['supported_devices'] = $item['supportedDevices'] ?? [];
                    $entry['file_size'] = $item['fileSizeBytes'] ?? null;
                    $entry['version'] = $item['version'] ?? '';
                    $entry['minimum_os'] = $item['minimumOsVersion'] ?? '';
                }

                if ($media === 'tvShow' || $kind === 'tv-episode') {
                    $entry['genre'] = $item['primaryGenreName'] ?? '';
                    $entry['description'] = $item['longDescription'] ?? $item['shortDescription'] ?? '';
                    $entry['content_advisory'] = $item['contentAdvisoryRating'] ?? '';
                    $entry['season'] = $item['seasonNumber'] ?? null;
                    $entry['episode'] = $item['episodeNumber'] ?? null;
                }

                // Common fields for all types
                $entry['artwork_url'] = $artwork;
                $entry['artwork_large'] = $artwork_large;
                $entry['artwork_small'] = $artwork_small;
                $entry['preview_url'] = $item['previewUrl'] ?? '';
                $entry['track_view_url'] = $item['trackViewUrl'] ?? $item['collectionViewUrl'] ?? '';
                $entry['price'] = $price;
                $entry['currency'] = $currency;
                $entry['formatted_price'] = $price !== null ? ($price === 0 ? 'Free' : $currency . ' ' . number_format($price, 2)) : '';
                $entry['is_free'] = $price === 0;
                $entry['release_date'] = $release_date;
                $entry['release_year'] = !empty($release_date) ? substr($release_date, 0, 4) : '';
